import numpy as np
from scipy.optimize import curve_fit

class ZeroNoiseExtrapolation:
    """
    Implement zero-noise extrapolation error mitigation.
    """

    def __init__(self, base_noise_rate=0.02):
        self.base_noise = base_noise_rate

    def simulate_noisy_expectation(self, true_value, noise_factor, n_shots=1000):
        """Simulate noisy measurement with scaled noise."""
        effective_noise = self.base_noise * noise_factor

        # Depolarizing noise: value -> (1-p)*value + p*0.5
        noisy_value = true_value * (1 - effective_noise) + 0.5 * effective_noise

        # Statistical noise from finite shots
        std = np.sqrt(noisy_value * (1 - noisy_value) / n_shots)
        measured = noisy_value + np.random.normal(0, std)

        return np.clip(measured, 0, 1)

    def extrapolate_linear(self, noise_factors, measurements):
        """Linear extrapolation to zero noise."""
        coeffs = np.polyfit(noise_factors, measurements, 1)
        return np.polyval(coeffs, 0)

    def extrapolate_exponential(self, noise_factors, measurements):
        """Exponential extrapolation to zero noise."""
        def exp_func(x, a, b):
            return a * np.exp(-b * x) + (1 - a)

        try:
            popt, _ = curve_fit(exp_func, noise_factors, measurements, 
                               p0=[0.3, 0.5], maxfev=5000)
            return exp_func(0, *popt)
        except:
            return self.extrapolate_linear(noise_factors, measurements)

    def run_zne(self, true_value, noise_factors=[1.0, 1.5, 2.0, 2.5], n_shots=1000):
        """Run complete ZNE procedure."""
        # Measure at all noise levels
        measurements = []
        for nf in noise_factors:
            meas = self.simulate_noisy_expectation(true_value, nf, n_shots)
            measurements.append(meas)

        # Extrapolate
        linear = self.extrapolate_linear(noise_factors, measurements)
        exponential = self.extrapolate_exponential(noise_factors, measurements)

        return {
            'true': true_value,
            'unmitigated': measurements[0],
            'linear': linear,
            'exponential': exponential,
            'noise_factors': noise_factors,
            'measurements': measurements,
            'error_unmitigated': abs(measurements[0] - true_value),
            'error_linear': abs(linear - true_value),
            'error_exponential': abs(exponential - true_value)
        }

if __name__ == "__main__":
    zne = ZeroNoiseExtrapolation(base_noise_rate=0.03)

    result = zne.run_zne(true_value=0.3)
    print(f"True value: 0.3")
    print(f"Unmitigated: {result['unmitigated']:.4f} (error: {result['error_unmitigated']:.4f})")
    print(f"Linear ZNE: {result['linear']:.4f} (error: {result['error_linear']:.4f})")
    print(f"Exponential ZNE: {result['exponential']:.4f} (error: {result['error_exponential']:.4f})")

import numpy as np

class NISQFeasibilityAnalyzer:
    """
    Analyze NISQ feasibility for quantum Monte Carlo problems.
    """

    def __init__(self):
        self.max_qubits = 100
        self.max_depth = 80
        self.single_qubit_error = 0.001
        self.two_qubit_error = 0.01
        self.readout_error = 0.02

    def estimate_circuit_depth(self, n_qubits, n_grover):
        """Estimate circuit depth for QAE problem."""
        state_prep_depth = n_qubits * 3
        oracle_depth = n_qubits * 2
        diffusion_depth = n_qubits * 2

        grover_depth = state_prep_depth + oracle_depth + diffusion_depth
        total_depth = state_prep_depth + n_grover * grover_depth

        return total_depth

    def estimate_fidelity(self, depth):
        """Estimate circuit fidelity given depth."""
        avg_error = 0.7 * self.single_qubit_error + 0.3 * self.two_qubit_error
        circuit_fidelity = (1 - avg_error) ** depth
        total_fidelity = circuit_fidelity * (1 - self.readout_error)

        return total_fidelity

    def is_feasible(self, n_qubits, n_grover, min_fidelity=0.5):
        """Check if problem is feasible on NISQ hardware."""
        if n_qubits > self.max_qubits:
            return {
                'feasible': False,
                'reason': f'Exceeds max qubits ({self.max_qubits})',
                'depth': None,
                'fidelity': 0
            }

        depth = self.estimate_circuit_depth(n_qubits, n_grover)

        if depth > self.max_depth:
            return {
                'feasible': False,
                'reason': f'Exceeds max depth ({self.max_depth})',
                'depth': depth,
                'fidelity': self.estimate_fidelity(depth)
            }

        fidelity = self.estimate_fidelity(depth)

        if fidelity < min_fidelity:
            return {
                'feasible': False,
                'reason': f'Fidelity below threshold ({min_fidelity})',
                'depth': depth,
                'fidelity': fidelity
            }

        return {
            'feasible': True,
            'reason': 'All constraints satisfied',
            'depth': depth,
            'fidelity': fidelity
        }

    def recommend_parameters(self, target_accuracy, min_fidelity=0.5):
        """Recommend feasible parameters for target accuracy."""
        for n_qubits in range(3, self.max_qubits):
            max_grover = int(1 / target_accuracy)

            for n_grover in range(1, max_grover + 1):
                result = self.is_feasible(n_qubits, n_grover, min_fidelity)

                if result['feasible']:
                    est_accuracy = 1 / n_grover
                    if est_accuracy <= target_accuracy:
                        return {
                            'n_qubits': n_qubits,
                            'n_grover': n_grover,
                            'estimated_accuracy': est_accuracy,
                            'fidelity': result['fidelity']
                        }

        return None

    def hardware_improvement_needed(self, n_qubits, n_grover):
        """Calculate hardware improvements needed for infeasible problem."""
        depth = self.estimate_circuit_depth(n_qubits, n_grover)

        current_fidelity = self.estimate_fidelity(depth)

        target_fidelity = 0.5
        required_error = 1 - target_fidelity**(1/depth)

        return {
            'current_depth': depth,
            'current_fidelity': current_fidelity,
            'target_fidelity': target_fidelity,
            'required_error_rate': required_error,
            'current_avg_error': 0.7*self.single_qubit_error + 0.3*self.two_qubit_error,
            'improvement_factor': (0.7*self.single_qubit_error + 0.3*self.two_qubit_error) / required_error
        }

if __name__ == "__main__":
    analyzer = NISQFeasibilityAnalyzer()

    for n_q, n_g in [(4, 2), (6, 5), (8, 10), (10, 50)]:
        result = analyzer.is_feasible(n_q, n_g)
        status = "FEASIBLE" if result['feasible'] else "INFEASIBLE"
        print(f"n_qubits={n_q}, n_grover={n_g}: {status} (fidelity={result['fidelity']:.2%})")

    rec = analyzer.recommend_parameters(target_accuracy=0.05)
    if rec:
        print(f"\nRecommended: n_qubits={rec['n_qubits']}, n_grover={rec['n_grover']}")
